+/// Maximum receipt chain length before oldest entries are evicted.
+const MAX_RECEIPT_CHAIN: usize = 8192;
+
+fn push_bounded<T>(items: &mut Vec<T>, item: T, cap: usize) {
+    items.push(item);
+    if items.len() > cap {
+        let overflow = items.len() - cap;
+        items.drain(0..overflow);
+    }
+}
